Use ASP.NET Core's **`WebApplicationFactory<T>`** — it hosts your app in-memory and gives you an `HttpClient` that talks to it without opening real network ports.

**1. Add the test package:**

```bash
dotnet add reference ../src/MyMcpServer.csproj
dotnet add package Microsoft.AspNetCore.Mvc.Testing
```

**2. Write a test class:**

```csharp
using System.Net.Http.Json;
using Microsoft.AspNetCore.Mvc.Testing;
using Xunit;

public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2025-03-26",
            body.GetProperty("result")
                .GetProperty("protocolVersion")
                .GetString());
    }

    [Fact]
    public async Task ToolsCall_ExecutesTool()
    {
        // Initialize first (stateful session may require it)
        await InitializeSession();

        var request = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/call",
            @params = new
            {
                name = "my-tool",
                arguments = new { input = "hello" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var content = body.GetProperty("result")
                         .GetProperty("content")[0];
        Assert.Equal("text", content.GetProperty("type").GetString());
    }
}
```

**Key points:**

- **No real port** — `WebApplicationFactory` uses an in-memory `TestServer` under the hood.
- **Full pipeline** — middleware, DI, routing, serialization all run exactly as in production.
- **SSE/Streamable HTTP** — for streaming endpoints, use `SendAsync` with `HttpCompletionOption.ResponseHeadersRead` and read the response stream line-by-line.
- **Override services** — use `factory.WithWebHostBuilder(b => b.ConfigureServices(...))` to swap in mocks (e.g., a fake database).
- Make sure `Program` is accessible to the test project (add `InternalsVisibleTo` or a `public partial class Program { }` marker).
